+export async function upsertWorkspaceDependencyCache(
+  db: D1Database,
+  input: {
+    id: string;
+    workspaceId: string;
+    cacheKey: string;
+    manager: WorkspacePackageManager;
+    managerVersion: string | null;
+    projectRoot: string;
+    lockfileName: string | null;
+    lockfileSha256: string | null;
+    artifactKey: string;
+    artifactSha256: string;
+    artifactBytes: number;
+  }
+): Promise<void> {
+  const now = new Date().toISOString();
+  await db
+    .prepare(
+      `INSERT INTO workspace_dependency_caches (
+         id,
+         workspace_id,
+         cache_key,
+         manager,
+         manager_version,
+         project_root,
+         lockfile_name,
+         lockfile_sha256,
+         artifact_key,
+         artifact_sha256,
+         artifact_bytes,
+         last_used_at,
+         created_at,
+         updated_at
+       )
+       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
+       ON CONFLICT(workspace_id, cache_key)
+       DO UPDATE SET
+         manager = excluded.manager,
+         manager_version = excluded.manager_version,
+         project_root = excluded.project_root,
+         lockfile_name = excluded.lockfile_name,
+         lockfile_sha256 = excluded.lockfile_sha256,
+         artifact_key = excluded.artifact_key,
+         artifact_sha256 = excluded.artifact_sha256,
+         artifact_bytes = excluded.artifact_bytes,
+         last_used_at = excluded.last_used_at,
+         updated_at = excluded.updated_at`
+    )
+    .bind(
+      input.id,
+      input.workspaceId,
+      input.cacheKey,
+      input.manager,
+      input.managerVersion,
+      input.projectRoot,
+      input.lockfileName,
+      input.lockfileSha256,
+      input.artifactKey,
+      input.artifactSha256,
+      input.artifactBytes,
+      now,
+      now,
+      now
+    )
+    .run();
+}
